import{isNegligible}from"./utils.js";const UnitsInteger=function(i,t){return Math.abs(t-i)},UnitsOrdinal=function(i,t){throw new Error("dc.units.ordinal should not be called - it is a placeholder")},UnitWithPrecision=function(i){function n(i,t){return t=Math.abs((t-i)/n.resolution),isNegligible(t-Math.floor(t))?Math.floor(t):Math.ceil(t)}return n.resolution=i,n};export{UnitsInteger,UnitsOrdinal,UnitWithPrecision};